import io
from azure.storage.blob import BlobServiceClient, BlobClient
import azure.functions as func

def main(req: func.HttpRequest) -> func.HttpResponse:
    if not req.query_params.get('blob_path'):
        return func.HttpResponse(f"Blob path is required.", status_code=400)

    blob_path = req.query_params['blob_path']

    try:
        blob_service_client = BlobServiceClient.from_connection_string("AZURE_STORAGE_CONNECTION_STRING")
        blob_client = blob_service_client.get_blob_client(container='your-container', blob=blob_path)
        download_stream = blob_client.download_blob().readall()
        file_content = download_stream.getvalue()
    except Exception as e:
        return func.HttpResponse(f"Error reading blob: {str(e)}", status_code=500)

    return func.HttpResponse(file_content)